package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withNormalValues() throws IOException {
        String result = csvFormat.format("value1", "value2", 3);
        assertNotNull(result);
        assertTrue(result.contains("value1"));
        assertTrue(result.contains("value2"));
        assertTrue(result.contains("3"));
    }

    @Test
    void testFormat_withNullValue() throws IOException {
        String result = csvFormat.format("value1", null, "value3");
        assertNotNull(result);
        assertTrue(result.contains("value1"));
        assertTrue(result.contains("value3"));
        // null may be empty or some representation, just check it does not throw
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format();
        assertNotNull(result);
        assertEquals("", result);
    }

    @Test
    void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Use reflection to create a proxy CSVFormat that returns a mocked CSVPrinter throwing IOException
        CSVFormat spyFormat = spy(csvFormat);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord(any());

        // Use reflection to get the constructor CSVPrinter(Writer, CSVFormat)
        Constructor<CSVPrinter> constructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        constructor.setAccessible(true);

        // When new CSVPrinter is created inside format(), we replace it by our mockPrinter
        // We achieve this by spying CSVFormat.format method to replace the CSVPrinter creation
        doAnswer(invocation -> {
            Object[] args = invocation.getArguments();
            Object[] values = (Object[]) args[0];
            // Instead of creating a real CSVPrinter, call printRecord on mockPrinter to simulate exception
            mockPrinter.printRecord(values);
            return "";
        }).when(spyFormat).format(any());

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            // Call the real method but replaced by spy
            spyFormat.format("value");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
